export interface GlossaryEntry {
  term: string;
  definition: string;
  whyItMatters: string;
  typicalRange: string;
  source: string;
}

// Adversarially-verified educational content (generated from the content workflow).
// Scientifically checked; do not edit by hand without re-verifying.
export const GLOSSARY: GlossaryEntry[] = [
  { term: "Kd (dissociation constant)", definition: "The equilibrium dissociation constant for a 1:1 ligand-target binding interaction (units of concentration, M), equal to the free ligand concentration at which half of the target binding sites are occupied at equilibrium. Lower Kd indicates higher binding affinity.", whyItMatters: "It directly quantifies binding affinity from biophysical methods (e.g., SPR, ITC), grounding potency claims in direct target binding rather than downstream functional response (unlike IC50/EC50).", typicalRange: "Assay- and target-dependent; no fixed scale. Drug-like binders commonly span roughly pM to uM, with lower values indicating tighter binding.", source: "ChEMBL standard activity type \"Kd\" (EMBL-EBI); standard biochemistry/biophysics convention (Langmuir 1:1 binding)." },
  { term: "EC50", definition: "The concentration of a compound that produces 50% of its maximal effect in a functional assay (the half maximal effective concentration; a measure of agonist/effector potency). It is the functional-response counterpart to IC50.", whyItMatters: "It is the standard potency measure for agonists and functional cellular responses, where binding alone does not capture activity.", typicalRange: "Assay-dependent; lower = more potent (n/a as an absolute scale).", source: "ChEMBL standard activity type (EMBL-EBI); pharmacology convention" },
  { term: "IC50", definition: "The concentration of a compound that produces 50% inhibition of a target's activity or a biological response in a given assay. It is an inhibitory potency measure that depends on assay conditions; for competitive enzyme inhibitors it shifts with substrate concentration relative to Km (Cheng-Prusoff relationship), which is why Ki (assay-independent) is often derived from it.", whyItMatters: "It is one of the most common experimental readouts for ranking inhibitor potency in screening and SAR, though it is condition-dependent and not directly comparable across assays unlike Ki.", typicalRange: "Assay-dependent; commonly reported in nM-uM, lower = more potent (n/a as an absolute scale).", source: "ChEMBL standard activity type (EMBL-EBI); standard pharmacology/biochemistry convention" },
  { term: "pChEMBL value", definition: "A standardized potency value defined as the negative base-10 logarithm of a molar activity concentration (-log10 of IC50, XC50, EC50, AC50, ED50, Ki, Kd, or Potency in molar units). It lets different assay endpoints be compared on one logarithmic scale, where higher means more potent (e.g., 1 nM IC50 = pChEMBL 9).", whyItMatters: "It normalizes heterogeneous bioactivity readouts so potencies from different assays and papers can be ranked and compared consistently.", typicalRange: "Roughly 4-11 for reported actives; higher = more potent. Computed only when standard type is one of the listed types, relation is '=', units are nM, value > 0, and the data validity comment is null or 'Manually validated'.", source: "ChEMBL Interface Documentation (EMBL-EBI) FAQ: chembl.gitbook.io/chembl-interface-documentation" },
  { term: "Ki (inhibition constant)", definition: "The equilibrium dissociation constant of an inhibitor-target complex (Ki = koff/kon), reflecting intrinsic binding affinity independent of substrate concentration. Unlike IC50, which depends on assay conditions, Ki can be derived from an IC50 by correcting for substrate (or radioligand) and Km/Kd via the Cheng-Prusoff relationship.", whyItMatters: "By removing the substrate/ligand-concentration dependence inherent in IC50, Ki provides an assay-condition-independent affinity value that enables cleaner cross-study comparison (though pooling Ki from heterogeneous sources still introduces measurement noise).", typicalRange: "Assay-dependent; lower = tighter binding, commonly pM to uM for drug-like inhibitors (no fixed absolute scale).", source: "ChEMBL standard activity type \"Ki\" (EMBL-EBI); Cheng Y-C & Prusoff WH, Biochem Pharmacol 1973;22(23):3099-3108 (PMID 4202581)" },
  { term: "TPSA (Topological Polar Surface Area)", definition: "A calculated estimate of a molecule's polar surface area, computed as a sum of tabulated fragment contributions from polar atoms (primarily N and O and their attached hydrogens), expressed in square angstroms. It correlates with passive membrane permeability and hydrogen-bonding capacity.", whyItMatters: "It predicts permeability and absorption, commonly used to flag poor intestinal absorption and limited blood-brain-barrier penetration.", typicalRange: "Reported in A^2; common guidance: <=140 A^2 for good oral/intestinal absorption, <=90 A^2 for CNS/blood-brain-barrier penetration.", source: "Ertl, Rohde & Selzer, J Med Chem 2000, 43(20):3714-3717" },
  { term: "QED (Quantitative Estimate of Drug-likeness)", definition: "A composite score combining desirability functions over eight molecular properties (molecular weight, ALogP, TPSA, H-bond donors, H-bond acceptors, aromatic rings, rotatable bonds, and structural alerts) via their geometric mean into a single value from 0 to 1. Values near 1 indicate property profiles resembling approved oral drugs.", whyItMatters: "It provides a single, transparent drug-likeness ranking that integrates multiple physicochemical properties using smooth desirability functions rather than relying on hard pass/fail cutoffs.", typicalRange: "0-1; higher = more drug-like. Approved oral drugs cluster toward the higher end; QED is a continuous desirability score with no fixed pass/fail cutoff.", source: "Bickerton et al., 'Quantifying the chemical beauty of drugs', Nature Chemistry 4, 90-98 (2012); RDKit rdkit.Chem.QED module" },
  { term: "Lipinski Rule of Five (Ro5)", definition: "A heuristic for likely oral bioavailability flagging molecules with MW > 500 Da, cLogP > 5, more than 5 H-bond donors (sum of N-H and O-H bonds), or more than 10 H-bond acceptors (sum of N and O atoms). Poor oral absorption/permeability is more likely when a compound violates 2 or more of these criteria (i.e., it is acceptable with no more than one violation); substrates of biological transporters are recognized exceptions.", whyItMatters: "It is a fast first-pass filter for whether a small molecule has properties compatible with oral drug development.", typicalRange: "MW <=500 Da, cLogP <=5, HBD <=5, HBA <=10; <=1 violation is acceptable.", source: "Lipinski, Lombardo, Dominy & Feeney, Adv Drug Deliv Rev 1997, 23:3-25 (reprinted, not revised, in vol. 46:3-26, 2001)" },
  { term: "cLogP / AlogP", definition: "Calculated estimates of the octanol-water partition coefficient (logP), a measure of lipophilicity; cLogP and AlogP are different computational methods (fragment-based vs atom-based, respectively) for predicting it. Higher values indicate a more lipophilic (less water-soluble) molecule.", whyItMatters: "Lipophilicity strongly influences solubility, permeability, off-target binding, and metabolic clearance, making it central to drug-likeness assessment.", typicalRange: "Unitless; Lipinski's Rule of 5 flags logP > 5 as a violation (i.e., favors <=5); a favorable oral drug-like range is often cited as roughly 1-3 (sometimes 2-3).", source: "cLogP: Hansch-Leo fragment method (BioByte/Daylight). AlogP: Ghose-Crippen atomic method, orig. Ghose & Crippen J Comput Chem 1986/1988, reparametrized in Ghose, Viswanadhan & Wendoloski, J Phys Chem A 1998, 102:3762; RDKit reports the related Wildman-Crippen (1999) variant. Ro5: Lipinski et al., Adv Drug Deliv Rev 1997." },
  { term: "Molecular weight (MW)", definition: "The sum of the average atomic weights of all atoms in a molecule, typically reported in daltons (Da), which is numerically equivalent to g/mol for practical purposes. For drug profiling and Rule-of-Five filtering, MW refers to the parent compound's average molecular mass (isotope-abundance-weighted); monoisotopic mass is a distinct quantity used mainly in mass spectrometry.", whyItMatters: "MW correlates with permeability, solubility, and synthetic tractability, and is one of the core Rule-of-Five filters.", typicalRange: "Ro5 threshold <=500 Da for oral small molecules; many oral drugs fall ~150-500 Da.", source: "Lipinski et al., Adv. Drug Deliv. Rev. 1997; computed property in ChEMBL/RDKit" },
  { term: "HBD / HBA (hydrogen bond donors / acceptors)", definition: "Counts of a molecule's hydrogen-bonding groups: HBD (donors) and HBA (acceptors). In Lipinski's original definition, HBD is the total number of N-H and O-H bonds (so an NH2 counts as 2), and HBA is the total count of all nitrogen and oxygen atoms (a deliberately crude surrogate that includes some non-accepting atoms). They quantify a molecule's hydrogen-bonding capacity.", whyItMatters: "High H-bonding capacity raises the desolvation penalty for crossing lipid membranes, reducing passive permeability and oral absorption, which is why HBD and HBA are two of the four Rule-of-Five parameters.", typicalRange: "Ro5 thresholds: HBD <=5 (sum of N-H and O-H bonds), HBA <=10 (sum of all N and O atoms). Note: more refined cheminformatics definitions (e.g., RDKit NumHDonors/NumHAcceptors, or Lipinski-specific functions) count atoms/groups differently and give different values.", source: "Lipinski et al., Adv. Drug Deliv. Rev. 1997 (Rule of Five); also a standard computed property in ChEMBL and RDKit." },
  { term: "Progression-free survival (PFS)", definition: "The length of time during and after treatment that a patient lives with the disease without it worsening (progression) or the patient dying. It is a time-to-event clinical endpoint, usually reported as a median in months.", whyItMatters: "It is a widely used efficacy endpoint that can read out sooner than overall survival, informing both regulatory and clinical decisions.", typicalRange: "Reported as time (e.g., median months); disease- and line-of-therapy-dependent (n/a as an absolute scale).", source: "FDA Clinical Trial Endpoints guidance; NCI Dictionary of Cancer Terms" },
  { term: "Likelihood of approval (LOA)", definition: "An estimated probability that a drug in development will ultimately reach regulatory approval, typically computed by multiplying historical phase-to-phase transition success rates for all remaining phases. It is a benchmark statistic, not a prediction for a specific molecule.", whyItMatters: "It frames the attrition risk of a development-stage program against historical base rates for prioritization and portfolio context.", typicalRange: "0-100%; published Phase I-to-approval estimates are roughly 8-14% overall (BIO/Informa 2011-2020 ~7.9%; Wong, Siah & Lo 2019 ~13.8%) and vary widely by indication (e.g., ~5% oncology to ~26% hematology).", source: "BIO/Informa/QLS clinical development success rate reports (e.g., Clinical Development Success Rates and Contributing Factors 2011-2020); Wong, Siah & Lo, Biostatistics 2019;20(2):273-286" },
  { term: "Objective response rate (ORR)", definition: "The proportion of patients in a trial achieving a predefined reduction in tumor burden, typically defined as complete response (CR) plus partial response (PR), most commonly assessed by RECIST 1.1 in solid tumors. It is a tumor-shrinkage efficacy endpoint, usually reported as a percentage; responses are generally required to persist for a minimum interval (i.e., confirmed/durable).", whyItMatters: "It is a common early-signal efficacy measure in oncology trials, can be assessed in single-arm studies, and is used to support both accelerated and (when response magnitude and duration are clinically meaningful) regular approvals.", typicalRange: "0-100%; context-dependent (no universal 'good' threshold).", source: "FDA guidance \"Clinical Trial Endpoints for the Approval of Cancer Drugs and Biologics\" (2018); RECIST 1.1 (Eisenhauer et al., Eur J Cancer 2009;45:228-247)" },
  { term: "Open Targets association score", definition: "A heuristic measure of the strength of evidence linking a target (gene/protein) to a disease in the Open Targets Platform, computed as a weighted harmonic sum of underlying evidence, reported at the data source, data type, and overall levels. It reflects the quantity and strength of available evidence rather than the confidence or causal certainty of the association.", whyItMatters: "It lets researchers rank and prioritize candidate targets for a disease across heterogeneous evidence types (genetic, somatic, drug, pathway, literature) in a single comparable value.", typicalRange: "0 to 1 (continuous; higher = more/stronger evidence). No official \"significance\" threshold is defined; the documentation describes it as a heuristic based on availability of data and cautions it should not be interpreted as a confidence score for the association.", source: "Open Targets Platform Documentation, \"Target–disease associations\" (https://platform-docs.opentargets.org/associations); see also Ochoa et al., Nucleic Acids Research 2021, 49(D1):D1302–D1310." },
  { term: "Target tractability", definition: "Target tractability is the assessed likelihood that a biological target (e.g., a protein) can be successfully modulated by a specific therapeutic modality—such as a small molecule, antibody, or other drug class—based on properties like the presence of suitable binding pockets, structural features, and precedent. It is modality-specific, so a target may be considered tractable for one approach (e.g., antibodies against a cell-surface protein) yet intractable for another (e.g., small molecules against a flat protein-protein interaction interface).", whyItMatters: "Tractability assessment helps prioritize targets early in drug discovery by flagging whether a viable drug can realistically be developed before substantial resources are committed.", typicalRange: "n/a (qualitative/categorical bucketing rather than a single numeric scale; e.g., Open Targets groups evidence into modality-specific tractability \"buckets\")", source: "Open Targets Platform target tractability documentation (platform-docs.opentargets.org/target/tractability), which implements the framework of Brown KK, Hann MM, Lakdawala AS, Santos R, Thomas PJ, Todd K, \"Approaches to target tractability assessment – a practical perspective,\" MedChemComm, 2018, 9(4):606–613 (DOI 10.1039/C7MD00633K). For the foundational concept of \"druggability,\" see Hopkins AL & Groom CR, \"The druggable genome,\" Nature Reviews Drug Discovery, 2002, 1:727–730." },
  { term: "Veber rule (oral bioavailability)", definition: "A set of empirical criteria predicting good oral bioavailability in rats, derived from GlaxoSmithKline (formerly SmithKline Beecham) compound data, stating that molecules with (1) 10 or fewer rotatable bonds and (2) a polar surface area no greater than 140 Å² (or, equivalently, 12 or fewer total hydrogen-bond donors plus acceptors) tend to have favorable oral absorption. The rule emphasizes molecular flexibility and polar surface area as determinants of bioavailability beyond Lipinski's molecular-weight and lipophilicity descriptors.", whyItMatters: "It provides additional, easily computed flexibility and polarity filters used alongside Lipinski's Rule of Five to flag orally administered drug candidates at risk of poor absorption.", typicalRange: "Rotatable bonds <= 10; polar surface area (PSA) <= 140 Angstrom^2; alternatively total H-bond count (donors + acceptors) <= 12", source: "Veber DF, Johnson SR, Cheng HY, Smith BR, Ward KW, Kopple KD. \"Molecular Properties That Influence the Oral Bioavailability of Drug Candidates.\" J Med Chem. 2002;45(12):2615-2623. doi:10.1021/jm020017n" },
  { term: "Blood-brain barrier (BBB) permeability heuristic", definition: "A set of physicochemical rules-of-thumb used to estimate a small molecule's likelihood of crossing the blood-brain barrier by passive diffusion, typically favoring lower molecular weight, moderate lipophilicity, fewer hydrogen-bond donors/acceptors, and low polar surface area. Common implementations include calculated descriptors such as the CNS multiparameter optimization (MPO) score, which combines six properties (calculated logP, calculated logD at pH 7.4, molecular weight, topological polar surface area, hydrogen-bond donor count, and the pKa of the most basic center), as well as simpler topological polar surface area and hydrogen-bond-donor cutoffs.", whyItMatters: "It provides an early, low-cost filter for prioritizing CNS-targeted drug candidates and de-prioritizing molecules unlikely to reach brain tissue, before resource-intensive in vivo permeability testing.", typicalRange: "Heuristic-dependent; e.g., the Pfizer CNS MPO score ranges 0-6 with higher values indicating more favorable CNS properties (in the source, marketed CNS drugs were enriched at scores >=4). Commonly cited passive-permeability-favoring descriptor guidance includes topological polar surface area below roughly 90 angstrom-squared and reduced hydrogen-bond donor count (often <3), though exact cutoffs vary by source and are not absolute.", source: "Wager TT, Hou X, Verhoest PR, Villalobos A. \"Moving beyond rules: the development of a central nervous system multiparameter optimization (CNS MPO) approach to enable alignment of druglike properties.\" ACS Chem Neurosci. 2010;1(6):435-449. doi:10.1021/cn100008c" },
  { term: "Hazard ratio (HR)", definition: "The hazard ratio is the ratio of the hazard rates (instantaneous event rates) between two groups in a time-to-event (survival) analysis, typically estimated from the Cox proportional hazards model. It quantifies the relative risk of an event occurring at any instant in the treatment group versus the comparator, assuming the ratio is constant over time (proportional hazards).", whyItMatters: "It is the standard summary measure of treatment effect in oncology and other survival endpoints (e.g., overall survival, progression-free survival), enabling comparison of event risk over time rather than at a single fixed point.", typicalRange: "HR > 0; HR = 1 indicates no difference in hazard, HR < 1 indicates lower hazard (often favoring treatment) and HR > 1 indicates higher hazard. No universal \"significance\" cutoff exists; interpretation depends on the confidence interval and clinical context.", source: "Cox DR. Regression Models and Life-Tables. Journal of the Royal Statistical Society, Series B (Methodological). 1972;34(2):187-220 (article 187-202; with discussion to 220)." },
  { term: "Combination index (Chou-Talalay)", definition: "A quantitative measure of drug interaction derived from the median-effect equation and the multiple drug-effect (combination index) equation, where for two drugs CI = (D)1/(Dx)1 + (D)2/(Dx)2, with each term being the dose of a drug used in combination divided by the dose of that drug needed to produce the same effect level alone. This two-term equation corresponds to the mutually exclusive (classic isobologram) case; a mutually nonexclusive form adds a third term, [(D)1(D)2]/[(Dx)1(Dx)2]. The index summarizes whether a combination's observed effect is greater than, equal to, or less than the dose-additive expectation predicted by the mass-action law model.", whyItMatters: "It provides a standardized, effect-level-specific way to classify drug combinations as synergistic, additive, or antagonistic rather than relying on subjective judgment.", typicalRange: "CI < 1 indicates synergism, CI = 1 indicates an additive effect, and CI > 1 indicates antagonism (Chou's finer grading further subdivides these ranges).", source: "Chou TC. \"Theoretical basis, experimental design, and computerized simulation of synergism and antagonism in drug combination studies.\" Pharmacol Rev. 2006;58(3):621-681. doi:10.1124/pr.58.3.10. (Foundational method: Chou TC, Talalay P. Adv Enzyme Regul. 1984;22:27-55.)" }
];

export function lookup(term: string): GlossaryEntry | undefined {
  const k = term.trim().toLowerCase();
  return GLOSSARY.find((g) => g.term.toLowerCase() === k)
    ?? GLOSSARY.find((g) => g.term.toLowerCase().includes(k) || k.includes(g.term.toLowerCase()));
}
